import * as anchor from "@coral-xyz/anchor";
import { BN, AnchorError } from "@coral-xyz/anchor";

import {
  Keypair,
  LAMPORTS_PER_SOL,
  PublicKey,
  SystemProgram,
} from "@solana/web3.js";
import { assert, expect } from "chai";
// Note: Shitmarket type is generated by `anchor build` into target/types/shitmarket.json
// Until the first build runs we define a minimal alias so TypeScript is happy.
type Shitmarket = any; // replaced with `import { Shitmarket } from "../target/types/shitmarket"` after `anchor build`


// ─────────────────────────────────────────────
//  Helpers
// ─────────────────────────────────────────────

async function airdrop(
  provider: anchor.AnchorProvider,
  pubkey: PublicKey,
  sol: number
) {
  const sig = await provider.connection.requestAirdrop(
    pubkey,
    sol * LAMPORTS_PER_SOL
  );
  await provider.connection.confirmTransaction(sig, "confirmed");
}

function deriveConfig(programId: PublicKey): [PublicKey, number] {
  return PublicKey.findProgramAddressSync(
    [Buffer.from("platform_config")],
    programId
  );
}

function deriveRoom(
  tokenMint: PublicKey,
  creator: PublicKey,
  programId: PublicKey,
  nonce: number = 0
): [PublicKey, number] {
  return PublicKey.findProgramAddressSync(
    [Buffer.from("room"), tokenMint.toBuffer(), creator.toBuffer(), Buffer.from([nonce])],
    programId
  );
}

function deriveBet(
  room: PublicKey,
  user: PublicKey,
  side: "moon" | "jeet",
  programId: PublicKey
): [PublicKey, number] {
  const sideByte = side === "moon" ? 0 : 1;
  return PublicKey.findProgramAddressSync(
    [Buffer.from("bet"), room.toBuffer(), user.toBuffer(), Buffer.from([sideByte])],
    programId
  );
}

function deriveEscrow(room: PublicKey, programId: PublicKey): [PublicKey, number] {
  return PublicKey.findProgramAddressSync(
    [Buffer.from("escrow"), room.toBuffer()],
    programId
  );
}

function deriveVault(programId: PublicKey): [PublicKey, number] {
  return PublicKey.findProgramAddressSync(
    [Buffer.from("vault")],
    programId
  );
}

function deriveUserReferral(user: PublicKey, programId: PublicKey): [PublicKey, number] {
  return PublicKey.findProgramAddressSync(
    [Buffer.from("user_referral"), user.toBuffer()],
    programId
  );
}

function deriveReferralState(referrer: PublicKey, programId: PublicKey): [PublicKey, number] {
  return PublicKey.findProgramAddressSync(
    [Buffer.from("referral_state"), referrer.toBuffer()],
    programId
  );
}



// Mock token mint — we only store its pubkey on-chain, no real SPL mint needed
const MOCK_TOKEN_MINT = Keypair.generate().publicKey;
const MOCK_TOKEN_NAME = "PEPE5";
const MOCK_PRICE_FEED = Keypair.generate();
const MOCK_OPENING_PRICE = new BN("150000000000000"); // $150.00 mock price scaled by 1e12

async function createFakePythFeedAccount(provider: anchor.AnchorProvider, feedKeypair: Keypair) {
  const lamports = await provider.connection.getMinimumBalanceForRentExemption(2048);
  const tx = new anchor.web3.Transaction().add(
    SystemProgram.createAccount({
      fromPubkey: provider.wallet.publicKey,
      newAccountPubkey: feedKeypair.publicKey,
      lamports,
      space: 2048,
      programId: SystemProgram.programId,
    })
  );
  await provider.sendAndConfirm(tx, [feedKeypair]);
}

